import sys
from collections import deque

def main():
    n, s, r = map(int, sys.stdin.readline().split())
    a = list(map(int, sys.stdin.readline().split()))

    ans = 0
    qmin = deque()
    qmax = deque()
    sum = 0

    for i in range(n):
        while qmin and a[i] < a[qmin[-1]]:
            qmin.pop()
        qmin.append(i)

        while qmax and a[i] > a[qmax[-1]]:
            qmax.pop()
        qmax.append(i)

        while a[qmax[0]] - a[qmin[0]] > r:
            sum -= a[qmin[0] if qmin[0] < qmax[0] else qmax[0]]
            if qmin[0] < qmax[0]:
                qmin.popleft()
            else:
                qmax.popleft()

        while sum > s:
            sum -= a[i - len(qmin) + 1]
            if qmin[0] == i - len(qmin) + 1:
                qmin.popleft()
            if qmax[0] == i - len(qmax) + 1:
                qmax.popleft()

        ans += len(qmin)
        sum += a[i]

    print(ans)

if __name__ == "__main__":
    main()
